using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Preserve the old name so existing documents and direct SQL queries
            // (e.g. WHERE c.Discriminator = 'Product') continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 removed the discriminator from the JSON id property.
            // Preserve the old "Product|123" format so FindAsync and point-reads
            // can locate the 500K existing documents written by EF Core 8.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex is no longer silently ignored — it throws at startup in EF Core 9.
        // Cosmos DB indexing is managed via the container's indexing policy (Azure Portal / Bicep).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

